    // Check if the req.params object exists
    if (req.params) {
        // Check if any of the route parameters have a non-empty value
        if (Object.keys(req.params).some(key => req.params[key].length > 0)) {
            // Continue executing the route
            next();
        } else {
            // Return a 400 Bad Request error
