// Define the validateRouteParamsMiddleware function
function validateRouteParamsMiddleware(req, res, next) {
    // Check if the req.params object exists
    if (req.params) {
        // Check if all route parameters have a non-empty value
        if (Object.keys(req.params).every(key => req.params[key].length > 0)) {
            // Continue executing the route
            next();
        } else {
            // Return a 400 Bad Request error
            res.status(400).json({ error: 'Missing route parameter', statusCode: 400 });
        }
    } else {
        // Return a 400 Bad Request error
        res.status(400).json({ error: 'Missing route parameter', statusCode: 400 });
    }
}

// Export the middleware function
module.exports = validateRouteParamsMiddleware;
